4	interface TabsContextType {
5	  value: string;
6	  onValueChange: (value: string) => void;
7	}
8	
9	const TabsContext = React.createContext<TabsContextType>({
10	  value: "",
11	  onValueChange: () => {}
12	});
13	
14	interface TabsProps extends React.HTMLAttributes<HTMLDivElement> {
15	  defaultValue?: string;
16	  value?: string;
17	  onValueChange?: (value: string) => void;
18	}
19	
20	const Tabs = React.forwardRef<HTMLDivElement, TabsProps>(
21	  ({ className, defaultValue = "", value, onValueChange, children, ...props }, ref) => {
22	    const [internalValue, setInternalValue] = React.useState(defaultValue);
23	    const controlledValue = value !== undefined ? value : internalValue;
24	
25	    const handleChange = (newValue: string) => {
26	      if (value === undefined) setInternalValue(newValue);
27	      onValueChange?.(newValue);
28	    };
29	
30	    return (
31	      <TabsContext.Provider value={{ value: controlledValue, onValueChange: handleChange }}>
32	        <div
33	          ref={ref}
34	          data-slot="tabs"
35	          className={cn("flex flex-col gap-2", className)}
36	          {...props}>
37	          
38	          {children}
39	        </div>
40	      </TabsContext.Provider>);
41	
42	  }
43	);
44	Tabs.displayName = "Tabs";
45	
46	interface TabsListProps extends React.HTMLAttributes<HTMLDivElement> {
47	  variant?: "default" | "line";
48	}
49	
50	const TabsList = React.forwardRef<HTMLDivElement, TabsListProps>(
51	  ({ className, variant = "default", ...props }, ref) =>
52	  <div
53	    ref={ref}
54	    data-slot="tabs-list"
55	    data-variant={variant}
56	    role="tablist"
57	    className={cn(
58	      "inline-flex h-8 w-fit items-center justify-center rounded-lg p-[3px] text-muted-foreground",
59	      variant === "default" ? "bg-muted" : "gap-1 bg-transparent rounded-none",
60	      className
61	    )}
62	    {...props} />
63	
64	
65	);
66	TabsList.displayName = "TabsList";
67	
68	interface TabsTriggerProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
69	  value: string;
70	}
71	
72	const TabsTrigger = React.forwardRef<HTMLButtonElement, TabsTriggerProps>(
73	  ({ className, value: tabValue, ...props }, ref) => {
74	    const { value, onValueChange } = React.useContext(TabsContext);
75	    const isActive = value === tabValue;
76	
77	    return (
78	      <button
79	        ref={ref}
80	        type="button"
81	        role="tab"
82	        data-slot="tabs-trigger"
83	        data-active={isActive || undefined}
84	        aria-selected={isActive}
85	        onClick={() => onValueChange(tabValue)}
86	        className={cn(
87	          "relative inline-flex h-[calc(100%-1px)] flex-1 items-center justify-center gap-1.5 rounded-md border border-transparent px-1.5 py-0.5 text-sm font-medium whitespace-nowrap text-foreground/60 transition-all hover:text-foreground focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4",
88	          isActive && "bg-background text-foreground shadow-sm dark:border-input dark:bg-input/30",
89	          className
90	        )}
91	        {...props} />);
92	
93	
94	  }
95	);
96	TabsTrigger.displayName = "TabsTrigger";
97	
98	interface TabsContentProps extends React.HTMLAttributes<HTMLDivElement> {
99	  value: string;
100	}
101	
102	const TabsContent = React.forwardRef<HTMLDivElement, TabsContentProps>(
103	  ({ className, value: tabValue, ...props }, ref) => {
104	    const { value } = React.useContext(TabsContext);
105	    if (value !== tabValue) return null;
