368-
369-```python
370-# backend/app/api/generation.py
371-from fastapi import APIRouter
372-from fastapi.responses import StreamingResponse
373-
374-router = APIRouter()
375-
376-@router.post("/stream")
377-async def generate_stream(request: GenerationRequest):
378-    async def event_generator():
379-        async for chunk in ai_service.generate_stream(
380-            model_key=request.model,
381-            prompt=request.prompt,
382-            system_prompt=request.system_prompt,
383-        ):
384-            yield f"data: {json.dumps({'text': chunk})}\n\n"
385-        yield f"data: {json.dumps({'done': True})}\n\n"
386-
387-    return StreamingResponse(event_generator(), media_type="text/event-stream")
388-```
389-
390-```typescript
391-// frontend/src/services/streaming.ts
392-export async function* streamGeneration(request: GenerationRequest): AsyncGenerator<string> {
393-  const response = await fetch('/api/generation/stream', {
394-    method: 'POST',
395-    headers: { 'Content-Type': 'application/json' },
396-    body: JSON.stringify(request),
397-  });
398-  const reader = response.body!.getReader();
399-  const decoder = new TextDecoder();
400-  while (true) {
401-    const { done, value } = await reader.read();
402-    if (done) break;
403-    const text = decoder.decode(value);
404-    for (const line of text.split('\n')) {
405-      if (line.startsWith('data: ')) {
406-        const data = JSON.parse(line.slice(6));
407-        if (data.done) return;
408-        yield data.text;
409-      }
410-    }
411-  }
412-}
413-```
414-
415-**Key Points:**
416-- FastAPI `StreamingResponse` with SSE format (`data: ...\n\n`)
417-- React consumes via `ReadableStream` reader
418-- JSON-encoded chunks allow metadata alongside text
419-- Terminal `done` event signals completion
420-- Dramatically improves perceived performance for content generation
