1	import { useCallback, useEffect, useState } from "react";
2	import { api } from "../services/api";
3	import type { ContentItem, ContentStatus, ContentType, PaginatedResponse } from "../types/content";
4	
5	interface ContentFilters {
6	  status?: ContentStatus | "";
7	  content_type?: ContentType | "";
8	  page?: number;
9	  page_size?: number;
10	}
11	
12	interface UseContentReturn {
13	  items: ContentItem[];
14	  total: number;
15	  loading: boolean;
16	  error: string | null;
17	  filters: ContentFilters;
18	  setFilters: (filters: ContentFilters) => void;
19	  refresh: () => Promise<void>;
20	  getById: (id: string) => Promise<ContentItem>;
21	  create: (data: Partial<ContentItem>) => Promise<ContentItem>;
22	  update: (id: string, data: Partial<ContentItem>) => Promise<ContentItem>;
23	  remove: (id: string) => Promise<void>;
24	  transition: (id: string, status: ContentStatus) => Promise<ContentItem>;
25	}
26	
27	export function useContent(initialFilters: ContentFilters = {}): UseContentReturn {
28	  const [items, setItems] = useState<ContentItem[]>([]);
29	  const [total, setTotal] = useState(0);
30	  const [loading, setLoading] = useState(true);
31	  const [error, setError] = useState<string | null>(null);
32	  const [filters, setFilters] = useState<ContentFilters>({
33	    page: 1,
34	    page_size: 20,
35	    ...initialFilters,
36	  });
37	
38	  const buildParams = useCallback((): Record<string, string> => {
39	    const params: Record<string, string> = {};
40	    if (filters.status) params.status = filters.status;
41	    if (filters.content_type) params.content_type = filters.content_type;
42	    if (filters.page) params.page = String(filters.page);
43	    if (filters.page_size) params.page_size = String(filters.page_size);
44	    return params;
45	  }, [filters]);
46	
47	  const fetchItems = useCallback(async () => {
48	    setLoading(true);
49	    setError(null);
50	    try {
51	      const data = await api.get<PaginatedResponse<ContentItem>>(
52	        "/content",
53	        buildParams()
54	      );
55	      setItems(data.items);
56	      setTotal(data.total);
57	    } catch (err) {
58	      const message = err instanceof Error ? err.message : "Failed to fetch content";
59	      setError(message);
60	    } finally {
61	      setLoading(false);
62	    }
63	  }, [buildParams]);
64	
65	  useEffect(() => {
66	    void fetchItems();
67	  }, [fetchItems]);
68	
69	  const getById = useCallback(async (id: string): Promise<ContentItem> => {
70	    return api.get<ContentItem>(`/content/${id}`);
71	  }, []);
72	
73	  const create = useCallback(async (data: Partial<ContentItem>): Promise<ContentItem> => {
74	    const item = await api.post<ContentItem>("/content", data);
75	    void fetchItems();
76	    return item;
77	  }, [fetchItems]);
78	
79	  const update = useCallback(async (id: string, data: Partial<ContentItem>): Promise<ContentItem> => {
80	    const item = await api.put<ContentItem>(`/content/${id}`, data);
81	    void fetchItems();
82	    return item;
83	  }, [fetchItems]);
84	
85	  const remove = useCallback(async (id: string): Promise<void> => {
86	    await api.delete(`/content/${id}`);
87	    void fetchItems();
88	  }, [fetchItems]);
89	
90	  const transition = useCallback(async (id: string, status: ContentStatus): Promise<ContentItem> => {
91	    const item = await api.post<ContentItem>(`/content/${id}/transition`, { status });
92	    void fetchItems();
93	    return item;
94	  }, [fetchItems]);
95	
96	  return {
97	    items,
98	    total,
99	    loading,
100	    error,
101	    filters,
102	    setFilters,
103	    refresh: fetchItems,
104	    getById,
105	    create,
106	    update,
107	    remove,
108	    transition,
109	  };
110	}
