16	export function useGeneration(): UseGenerationReturn {
17	  const [status, setStatus] = useState<GenerationStatus>("idle");
18	  const [output, setOutput] = useState("");
19	  const [error, setError] = useState<string | null>(null);
20	  const controllerRef = useRef<AbortController | null>(null);
21	
22	  const cancel = useCallback(() => {
23	    controllerRef.current?.abort();
24	    controllerRef.current = null;
25	    setStatus("idle");
26	  }, []);
27	
28	  const reset = useCallback(() => {
29	    cancel();
30	    setOutput("");
31	    setError(null);
32	  }, [cancel]);
33	
34	  const generate = useCallback((request: GenerationRequest) => {
35	    controllerRef.current?.abort();
36	    setOutput("");
37	    setError(null);
38	    setStatus("generating");
39	
40	    const controller = createGenerationStream(
41	      "/generation/stream",
42	      request,
43	      {
44	        onToken: (text: string) => {
45	          setOutput((prev) => prev + text);
46	        },
47	        onDone: () => {
48	          controllerRef.current = null;
49	          setStatus("idle");
50	        },
51	        onError: (errorMsg: string) => {
52	          controllerRef.current = null;
53	          setError(errorMsg);
54	          setStatus("error");
55	        },
56	      }
57	    );
58	
59	    controllerRef.current = controller;
60	  }, []);
