15	
16	export function useValidation(): UseValidationReturn {
17	  const [result, setResult] = useState<ValidationResult | null>(null);
18	  const [history, setHistory] = useState<ValidationResult[]>([]);
19	  const [validating, setValidating] = useState(false);
