26	function getWeekDays(date: Date): Date[] {
27	  const start = new Date(date);
28	  start.setDate(start.getDate() - start.getDay());
29	  return Array.from({ length: 7 }, (_, i) => {
30	    const d = new Date(start);
31	    d.setDate(start.getDate() + i);
32	    return d;
33	  });
34	}
