36	function getMonthDays(date: Date): Date[] {
37	  const year = date.getFullYear();
38	  const month = date.getMonth();
39	  const firstDay = new Date(year, month, 1);
40	  const startOffset = firstDay.getDay();
41	  const start = new Date(firstDay);
42	  start.setDate(start.getDate() - startOffset);
43	
44	  const days: Date[] = [];
45	  for (let i = 0; i < 42; i++) {
46	    const d = new Date(start);
47	    d.setDate(start.getDate() + i);
48	    days.push(d);
49	  }
50	  return days;
51	}
