1	import type { ApiError } from "../types/content";
2	
3	const BASE_URL = import.meta.env.VITE_API_BASE_URL ?? "/api";
4	
5	class ApiClientError extends Error {
6	  status: number;
7	  detail: string;
8	
9	  constructor(status: number, detail: string) {
10	    super(detail);
11	    this.name = "ApiClientError";
12	    this.status = status;
13	    this.detail = detail;
14	  }
15	}
16	
17	async function handleResponse<T>(response: Response): Promise<T> {
18	  if (!response.ok) {
19	    let detail = `Request failed with status ${response.status}`;
20	    try {
21	      const error: ApiError = await response.json();
22	      detail = error.detail ?? detail;
23	    } catch {
24	      // Use default detail
25	    }
26	    throw new ApiClientError(response.status, detail);
27	  }
28	  return response.json() as Promise<T>;
29	}
30	
31	function buildUrl(path: string, params?: Record<string, string>): string {
32	  const url = `${BASE_URL}${path}`;
33	  if (!params) return url;
34	  const searchParams = new URLSearchParams(params);
35	  return `${url}?${searchParams.toString()}`;
36	}
37	
38	export const api = {
39	  async get<T>(path: string, params?: Record<string, string>): Promise<T> {
40	    const response = await fetch(buildUrl(path, params), {
41	      headers: { "Content-Type": "application/json" },
42	    });
43	    return handleResponse<T>(response);
44	  },
45	
46	  async post<T>(path: string, body?: unknown): Promise<T> {
47	    const response = await fetch(buildUrl(path), {
48	      method: "POST",
49	      headers: { "Content-Type": "application/json" },
50	      body: body != null ? JSON.stringify(body) : undefined,
51	    });
52	    return handleResponse<T>(response);
53	  },
54	
55	  async put<T>(path: string, body?: unknown): Promise<T> {
56	    const response = await fetch(buildUrl(path), {
57	      method: "PUT",
58	      headers: { "Content-Type": "application/json" },
59	      body: body != null ? JSON.stringify(body) : undefined,
60	    });
61	    return handleResponse<T>(response);
62	  },
63	
64	  async delete<T = void>(path: string): Promise<T> {
65	    const response = await fetch(buildUrl(path), {
66	      method: "DELETE",
67	      headers: { "Content-Type": "application/json" },
68	    });
69	    return handleResponse<T>(response);
70	  },
71	};
72	
73	export { ApiClientError };
